//! The canonical index: compose the two scanners into `specmap.json`
//! (PROP-014 §2.5) — derived, deterministic, committed, regenerated by
//! `specmap-rust` (or the project's wrapper), gated by `--check` the way
//! a generated-code check gates wire types.
//!
//! Beyond raw nodes and edges the index carries the **suspects table**
//! (PROP-014 §2.2, asymmetric invalidation): every edge pinned to an
//! older revision than its unit currently declares. Suspect detection
//! is intra-tree and therefore deterministic; the *unbumped-hash*
//! diagnostic ("content changed while `r` did not") needs the previous
//! index and is emitted as regeneration-time stderr, never stored.

specmark::scope!("spec://core-ai-native/mechanisms/PROP-014#index");

use std::collections::BTreeMap;
use std::path::{Path, PathBuf};

use crate::generated::specmap::{Specmap, Suspect, Warning};
use anyhow::{Context, Result};

use crate::config::Config;
use crate::mdspec;

/// Repo-relative location of the committed index.
pub const INDEX_REL_PATH: &str = "specmap.json";

/// Current index schema number. 2: canonical (house-style) URI
/// doc-paths, `spec_unit.file`, the `suspects` table.
pub const SCHEMA: u32 = 2;

fn verb_str(e: &crate::generated::specmap::Edge) -> &'static str {
    use crate::generated::specmap::EdgeVerb::*;
    match e.verb {
        Implements => "implements",
        Verifies => "verifies",
        Documents => "documents",
        Deviates => "deviates",
        Informs => "informs",
    }
}

fn verb_key(e: &crate::generated::specmap::Edge) -> u8 {
    use crate::generated::specmap::EdgeVerb::*;
    match e.verb {
        Implements => 0,
        Verifies => 1,
        Documents => 2,
        Deviates => 3,
        Informs => 4,
    }
}

/// Build the index for the tree under `root` with the built-in Rust
/// scanner. Pure function of the tree: same tree → same value.
pub fn build(root: &Path, cfg: &Config) -> Specmap {
    build_with_scanner(root, cfg, &crate::scanner::RustScanner)
}

/// Build the index with an explicit code scanner (the D3 seam): the
/// TypeScript stack injects its JSDoc scanner here, and a mixed tree
/// composes several through [`crate::scanner::CompositeScanner`]. The
/// markdown side, external-spec resolution, suspects, and ordering are
/// identical whichever scanner feeds the code half.
pub fn build_with_scanner(
    root: &Path,
    cfg: &Config,
    scanner: &dyn crate::scanner::CodeScanner,
) -> Specmap {
    let (mut spec_units, mut md_warnings) = mdspec::scan_spec_tree(root, cfg);
    let (mut code_items, mut edges, mut rs_warnings) = scanner.scan(root, cfg);
    // Installed packages' spec trees participate in RESOLUTION only
    // (PROP-014 §7.1): their units feed the revision map below — so an
    // edge into `spec://<pkg>/…` resolves instead of dangling, and its
    // pin can go suspect — but are never serialised into this project's
    // index (`spec_units` stays the project's own content, byte-stable).
    let external_units = mdspec::scan_external_units(root, cfg);

    let mut warnings = Vec::new();
    warnings.append(&mut md_warnings);
    warnings.append(&mut rs_warnings);

    // Asymmetric-invalidation analysis (PROP-014 §2.2). On a duplicate
    // anchor the first occurrence wins here; the duplicate itself is
    // already a warning from mdspec. Project units enter first, so a
    // namespace collision resolves in the project's favour.
    let mut unit_revisions: BTreeMap<&str, Option<u32>> = BTreeMap::new();
    for u in spec_units.iter().chain(external_units.iter()) {
        unit_revisions
            .entry(u.uri.as_str())
            .or_insert(u.revision.as_deref().copied());
    }
    let mut suspects: Vec<Suspect> = Vec::new();
    for e in &edges {
        match unit_revisions.get(e.uri.as_str()) {
            None => warnings.push(Warning {
                code: "dangling-edge".to_string(),
                message: format!(
                    "edge `{}` --{}--> `{}`: no spec unit carries this anchor",
                    e.fromSymbol,
                    verb_str(e),
                    e.uri
                ),
                file: e.file.clone(),
                line: e.line,
            }),
            Some(None) => {
                if let Some(p) = e.pinnedR.as_deref() {
                    warnings.push(Warning {
                        code: "pin-into-unmarked-unit".to_string(),
                        message: format!(
                            "edge `{}` pins r{p} but `{}` carries no kind/revision line yet",
                            e.fromSymbol, e.uri
                        ),
                        file: e.file.clone(),
                        line: e.line,
                    });
                }
            }
            Some(Some(rev)) => {
                if let Some(p) = e.pinnedR.as_deref() {
                    if p < rev {
                        suspects.push(Suspect {
                            fromSymbol: e.fromSymbol.clone(),
                            uri: e.uri.clone(),
                            pinnedR: *p,
                            currentR: *rev,
                            file: e.file.clone(),
                            line: e.line,
                        });
                    } else if p > rev {
                        warnings.push(Warning {
                            code: "pin-ahead-of-unit".to_string(),
                            message: format!(
                                "edge `{}` pins r{p} but `{}` is only at r{rev} — \
                                 a reverted spec or a typo'd pin",
                                e.fromSymbol, e.uri
                            ),
                            file: e.file.clone(),
                            line: e.line,
                        });
                    }
                }
            }
        }
    }

    // Canonical ordering — the determinism contract.
    spec_units.sort_by(|a, b| (&a.docPath, a.line).cmp(&(&b.docPath, b.line)));
    code_items.sort_by(|a, b| (&a.symbol, &a.file, a.line).cmp(&(&b.symbol, &b.file, b.line)));
    code_items.dedup_by(|a, b| a.symbol == b.symbol && a.file == b.file && a.line == b.line);
    edges.sort_by(|a, b| {
        (&a.fromSymbol, verb_key(a), &a.uri, &a.file, a.line).cmp(&(
            &b.fromSymbol,
            verb_key(b),
            &b.uri,
            &b.file,
            b.line,
        ))
    });
    suspects.sort_by(|a, b| {
        (&a.uri, &a.fromSymbol, &a.file, a.line).cmp(&(&b.uri, &b.fromSymbol, &b.file, b.line))
    });
    warnings.sort_by(|a, b| {
        (&a.file, a.line, &a.code, &a.message).cmp(&(&b.file, b.line, &b.code, &b.message))
    });

    Specmap {
        schema: SCHEMA,
        specUnits: spec_units,
        codeItems: code_items,
        edges,
        suspects,
        warnings,
    }
}

/// Canonical bytes: pretty JSON + trailing newline.
pub fn to_canonical_bytes(map: &Specmap) -> Result<String> {
    let mut s = serde_json::to_string_pretty(map).context("serialising specmap")?;
    s.push('\n');
    Ok(s)
}

pub fn index_path(root: &Path) -> PathBuf {
    root.join(INDEX_REL_PATH)
}

/// Classify the difference between the previously-committed index and
/// a freshly-built one — the regeneration-time drift report:
///
/// - **revision bumps** (`rN` → `rM`) with the suspect edges they
///   create (the drift-drill (a) signal);
/// - **unbumped hashes** — unit content changed while `r` stayed put:
///   *editorial, or forgot to bump?* (the drift-drill (b) signal;
///   GUIDE-SPEC-AUTHORING §4: bump, or mark the commit body
///   `spec-editorial: <anchor>`);
/// - unit/edge population changes, as counts.
pub fn classify_drift(old: &Specmap, new: &Specmap) -> Vec<String> {
    let mut lines = Vec::new();
    let old_units: BTreeMap<&str, (Option<u32>, &str)> = old
        .specUnits
        .iter()
        .map(|u| {
            (
                u.uri.as_str(),
                (u.revision.as_deref().copied(), u.contentHash.as_str()),
            )
        })
        .collect();
    let new_units: BTreeMap<&str, (Option<u32>, &str, &str)> = new
        .specUnits
        .iter()
        .map(|u| {
            (
                u.uri.as_str(),
                (
                    u.revision.as_deref().copied(),
                    u.contentHash.as_str(),
                    u.anchor.as_str(),
                ),
            )
        })
        .collect();

    for (uri, (new_rev, new_hash, anchor)) in &new_units {
        let Some((old_rev, old_hash)) = old_units.get(uri) else {
            continue;
        };
        if old_rev == new_rev {
            // A unit with no revision line has no revision discipline
            // to audit yet — hash movement there is plain text churn.
            if old_hash != new_hash
                && let Some(rev) = new_rev
            {
                lines.push(format!(
                    "unbumped-hash: `{uri}` content changed while the revision stayed \
                     at r{rev} — editorial, or forgot to bump? (bump `r`, or mark the \
                     commit body `spec-editorial: {anchor}`)"
                ));
            }
        } else {
            let fa = old_rev
                .map(|n| format!("r{n}"))
                .unwrap_or_else(|| "—".into());
            let fb = new_rev
                .map(|n| format!("r{n}"))
                .unwrap_or_else(|| "—".into());
            lines.push(format!("revision bump: `{uri}` {fa} → {fb}"));
            for s in &new.suspects {
                if s.uri == *uri {
                    lines.push(format!(
                        "  now SUSPECT: `{}` (pinned r{}) at {}:{} — re-affirm after review",
                        s.fromSymbol, s.pinnedR, s.file, s.line
                    ));
                }
            }
        }
    }

    let added = new_units
        .keys()
        .filter(|k| !old_units.contains_key(*k))
        .count();
    let removed = old_units
        .keys()
        .filter(|k| !new_units.contains_key(*k))
        .count();
    if added > 0 {
        lines.push(format!("units added: {added}"));
    }
    if removed > 0 {
        lines.push(format!("units removed: {removed}"));
    }
    let edge_key =
        |e: &crate::generated::specmap::Edge| format!("{}|{}|{}", e.fromSymbol, verb_str(e), e.uri);
    let old_edges: std::collections::BTreeSet<String> = old.edges.iter().map(edge_key).collect();
    let new_edges: std::collections::BTreeSet<String> = new.edges.iter().map(edge_key).collect();
    let e_added = new_edges.difference(&old_edges).count();
    let e_removed = old_edges.difference(&new_edges).count();
    if e_added > 0 {
        lines.push(format!("edges added: {e_added}"));
    }
    if e_removed > 0 {
        lines.push(format!("edges removed: {e_removed}"));
    }
    lines
}

fn load_committed(root: &Path) -> Option<Specmap> {
    let text = std::fs::read_to_string(index_path(root)).ok()?;
    serde_json::from_str(&text).ok()
}

/// Regenerate and write `specmap.json`. Returns (path, summary).
/// Emits the drift report against the previously-committed index to
/// stderr before overwriting.
pub fn write(root: &Path, cfg: &Config) -> Result<(PathBuf, Summary)> {
    write_with_scanner(root, cfg, &crate::scanner::RustScanner)
}

/// [`write`] with an explicit code scanner (the D3 seam).
pub fn write_with_scanner(
    root: &Path,
    cfg: &Config,
    scanner: &dyn crate::scanner::CodeScanner,
) -> Result<(PathBuf, Summary)> {
    let map = build_with_scanner(root, cfg, scanner);
    let summary = Summary::of(&map);
    if let Some(old) = load_committed(root) {
        for line in classify_drift(&old, &map) {
            eprintln!("  drift: {line}");
        }
    }
    let bytes = to_canonical_bytes(&map)?;
    let path = index_path(root);
    std::fs::write(&path, bytes).with_context(|| format!("writing {}", path.display()))?;
    Ok((path, summary))
}

/// `--check`: regenerate and byte-compare against the committed file.
/// On drift the error carries the classified report, so the drill
/// signals (revision bumps → suspects; unbumped hashes) are visible at
/// the gate itself.
pub fn check(root: &Path, cfg: &Config) -> Result<std::result::Result<Summary, String>> {
    check_with_scanner(root, cfg, &crate::scanner::RustScanner)
}

/// [`check`] with an explicit code scanner (the D3 seam).
pub fn check_with_scanner(
    root: &Path,
    cfg: &Config,
    scanner: &dyn crate::scanner::CodeScanner,
) -> Result<std::result::Result<Summary, String>> {
    let map = build_with_scanner(root, cfg, scanner);
    let summary = Summary::of(&map);
    let fresh = to_canonical_bytes(&map)?;
    let path = index_path(root);
    let committed = std::fs::read_to_string(&path).with_context(|| {
        format!(
            "reading {} — run `specmap-rust` (or your project's wrapper) first",
            path.display()
        )
    })?;
    if fresh == committed {
        return Ok(Ok(summary));
    }
    let mut msg = format!("`{}` is out of date relative to the tree.", path.display());
    if let Ok(old) = serde_json::from_str::<Specmap>(&committed) {
        for line in classify_drift(&old, &map) {
            msg.push_str("\n  drift: ");
            msg.push_str(&line);
        }
    }
    msg.push_str(
        "\nRun `specmap-rust` (or your project's wrapper), review the drift, and commit the result.",
    );
    Ok(Err(msg))
}

/// Counts for the human one-liner.
#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub struct Summary {
    pub spec_units: usize,
    pub code_items: usize,
    pub edges: usize,
    pub suspects: usize,
    pub warnings: usize,
}

impl Summary {
    pub fn of(map: &Specmap) -> Self {
        Summary {
            spec_units: map.specUnits.len(),
            code_items: map.codeItems.len(),
            edges: map.edges.len(),
            suspects: map.suspects.len(),
            warnings: map.warnings.len(),
        }
    }
}

impl std::fmt::Display for Summary {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        write!(
            f,
            "{} spec units, {} tagged code items, {} edges, {} suspects, {} warnings",
            self.spec_units, self.code_items, self.edges, self.suspects, self.warnings
        )
    }
}

/// The vacuous-scan warning, one wording for every driver: `Some(message)`
/// when the scan produced no tagged code items at all, so the orphan
/// ratchet and the suspects table pass on an empty set. That is the silent
/// failure mode of `scan_roots` naming a parent directory instead of the
/// crate dirs themselves — a parent dir scans nothing and the gate greens
/// by vacuity (PROP-014 §2.5). Warning, not error: a freshly-initialised
/// project legitimately has nothing tagged yet.
///
/// ```
/// use specmap_core::index::{Summary, vacuity_warning};
///
/// let empty = Summary { spec_units: 3, code_items: 0, edges: 0, suspects: 0, warnings: 0 };
/// assert!(vacuity_warning(&empty).is_some());
///
/// let tagged = Summary { code_items: 1, ..empty };
/// assert!(vacuity_warning(&tagged).is_none());
/// ```
pub fn vacuity_warning(summary: &Summary) -> Option<String> {
    if summary.code_items > 0 {
        return None;
    }
    Some(
        "the scan found 0 tagged code items — the orphan gate and the suspects table are \
         green by vacuity; `scan_roots` entries must name crate dirs (or `<dir>/*` their \
         parent): a bare parent directory scans nothing (PROP-014 §2.5)"
            .to_string(),
    )
}

#[cfg(test)]
mod tests {
    use super::*;

    /// A small synthetic tree — several anchored units across two docs plus
    /// one tagged code item. Enough to exercise the inventory, the ordering
    /// invariant, and the edge-from-code path without assuming any particular
    /// host repository: specmap-core ships in the rust-ai-native package now,
    /// so `CARGO_MANIFEST_DIR` is no longer a substantial spec tree.
    fn synthetic_tree() -> tempfile::TempDir {
        let tmp = tempfile::tempdir().unwrap();
        let root = tmp.path();
        std::fs::create_dir_all(root.join("spec/modules")).unwrap();
        std::fs::write(
            root.join("spec/A.md"),
            "## Alpha {#alpha}\n`prop r1`\n\nbody\n\n## Beta {#beta}\n\nbody\n",
        )
        .unwrap();
        std::fs::write(
            root.join("spec/modules/B.md"),
            "## Gamma {#gamma}\n`req r1`\n\nbody\n",
        )
        .unwrap();
        let src = root.join("crates/x/src");
        std::fs::create_dir_all(&src).unwrap();
        std::fs::write(
            src.join("lib.rs"),
            "#[spec(implements = \"spec://project/A#alpha\", r = 1)]\npub fn f() {}\n",
        )
        .unwrap();
        tmp
    }

    /// PROP-014 §2.5: determinism is a tested property — index twice, assert
    /// byte-identical.
    #[test]
    fn index_is_deterministic() {
        let tmp = synthetic_tree();
        let a = to_canonical_bytes(&build(tmp.path(), &Config::default())).unwrap();
        let b = to_canonical_bytes(&build(tmp.path(), &Config::default())).unwrap();
        assert_eq!(a, b);
        assert!(a.ends_with('\n'));
    }

    #[test]
    fn node_inventory_is_ordered_and_house_style() {
        let tmp = synthetic_tree();
        let map = build(tmp.path(), &Config::default());
        assert!(map.specUnits.len() >= 3, "got {}", map.specUnits.len());
        // Ordering invariant: (doc_path, line) non-decreasing.
        assert!(
            map.specUnits
                .windows(2)
                .all(|w| (&w[0].docPath, w[0].line) <= (&w[1].docPath, w[1].line))
        );
        // House-style URIs: no `spec/` prefix, no `.md`.
        assert!(
            map.specUnits
                .iter()
                .all(|u| !u.uri.starts_with("spec://project/spec/") && !u.uri.contains(".md#"))
        );
        // The tagged code item produced its edge into the spec unit.
        assert!(
            map.edges.iter().any(|e| e.uri == "spec://project/A#alpha"),
            "expected an edge into spec://project/A#alpha"
        );
    }

    /// End-to-end over a synthetic tree: suspects, dangling edges and
    /// pin-ahead warnings all surface.
    #[test]
    fn suspects_dangling_and_pin_ahead_are_detected() {
        let tmp = tempfile::tempdir().unwrap();
        let root = tmp.path();
        std::fs::create_dir_all(root.join("spec")).unwrap();
        std::fs::write(
            root.join("spec/T.md"),
            "## The contract {#req-t}\n`req r2`\n\nIt MUST hold.\n",
        )
        .unwrap();
        let src_dir = root.join("crates/x/src");
        std::fs::create_dir_all(&src_dir).unwrap();
        std::fs::write(
            src_dir.join("lib.rs"),
            r#"
#[spec(implements = "spec://project/T#req-t", r = 1)]
pub fn stale() {}

#[spec(implements = "spec://project/T#req-t", r = 2)]
pub fn current() {}

#[spec(implements = "spec://project/T#req-t", r = 3)]
pub fn ahead() {}

#[spec(implements = "spec://project/T#req-missing", r = 1)]
pub fn dangling() {}
"#,
        )
        .unwrap();

        let map = build(root, &Config::default());
        assert_eq!(map.specUnits.len(), 1);
        assert_eq!(map.specUnits[0].uri, "spec://project/T#req-t");
        assert_eq!(map.edges.len(), 4);
        assert_eq!(map.suspects.len(), 1, "exactly the r1 pin is suspect");
        assert_eq!(map.suspects[0].fromSymbol, "x::stale");
        assert_eq!(map.suspects[0].pinnedR, 1);
        assert_eq!(map.suspects[0].currentR, 2);
        let codes: Vec<&str> = map.warnings.iter().map(|w| w.code.as_str()).collect();
        assert!(codes.contains(&"dangling-edge"), "{codes:?}");
        assert!(codes.contains(&"pin-ahead-of-unit"), "{codes:?}");
    }

    /// PROP-014 §7.1: an edge into an installed package's unit resolves
    /// through `[[external_specs]]` — no dangling warning, suspects work —
    /// while the external unit itself stays OUT of the serialised index.
    #[test]
    fn external_specs_resolve_edges_without_entering_the_index() {
        let tmp = tempfile::tempdir().unwrap();
        let root = tmp.path();
        std::fs::create_dir_all(root.join("spec")).unwrap();
        let ext = root.join("vibedeps/some-flow/0.3.0/spec/mechanisms");
        std::fs::create_dir_all(&ext).unwrap();
        std::fs::write(
            ext.join("ENGINE-X-v0.1.md"),
            "## Rules {#rules}\n`req r2`\n\nbody\n",
        )
        .unwrap();
        let src_dir = root.join("crates/x/src");
        std::fs::create_dir_all(&src_dir).unwrap();
        std::fs::write(
            src_dir.join("lib.rs"),
            r#"
#[spec(implements = "spec://some-flow/mechanisms/ENGINE-X-v0.1#rules", r = 1)]
pub fn stale_pin_into_external() {}

#[spec(implements = "spec://some-flow/mechanisms/MISSING#rules", r = 1)]
pub fn dangling_even_with_externals() {}
"#,
        )
        .unwrap();
        let cfg = Config {
            external_specs: vec![crate::config::ExternalSpec {
                namespace: "some-flow".into(),
                root: "vibedeps/some-flow/0.3.0/spec".into(),
            }],
            ..Config::default()
        };
        let map = build(root, &cfg);
        // The external unit is resolution-only: not inventoried.
        assert!(
            map.specUnits.is_empty(),
            "external units leaked into the index: {}",
            map.specUnits.len()
        );
        // The resolved edge dangles no more — and its stale pin is a suspect.
        let codes: Vec<&str> = map.warnings.iter().map(|w| w.code.as_str()).collect();
        assert_eq!(
            codes.iter().filter(|c| **c == "dangling-edge").count(),
            1,
            "only the truly-missing target dangles: {codes:?}"
        );
        assert_eq!(map.suspects.len(), 1);
        assert_eq!(map.suspects[0].pinnedR, 1);
        assert_eq!(map.suspects[0].currentR, 2);
    }

    #[test]
    fn drift_classification_reports_bumps_and_unbumped_hashes() {
        let tmp = tempfile::tempdir().unwrap();
        let root = tmp.path();
        std::fs::create_dir_all(root.join("spec")).unwrap();
        let src_dir = root.join("crates/x/src");
        std::fs::create_dir_all(&src_dir).unwrap();
        std::fs::write(
            src_dir.join("lib.rs"),
            "#[spec(implements = \"spec://project/T#req-t\", r = 1)]\npub fn f() {}\n",
        )
        .unwrap();

        std::fs::write(
            root.join("spec/T.md"),
            "## C {#req-t}\n`req r1`\n\nIt MUST hold.\n",
        )
        .unwrap();
        let old = build(root, &Config::default());

        // (b) editorial change, no bump → unbumped-hash.
        std::fs::write(
            root.join("spec/T.md"),
            "## C {#req-t}\n`req r1`\n\nIt MUST always hold.\n",
        )
        .unwrap();
        let edited = build(root, &Config::default());
        let report = classify_drift(&old, &edited);
        assert!(
            report.iter().any(|l| l.starts_with("unbumped-hash:")),
            "{report:?}"
        );

        // (a) semantic change + bump → revision bump + suspect listing.
        std::fs::write(
            root.join("spec/T.md"),
            "## C {#req-t}\n`req r2`\n\nIt MUST hold, monotonically.\n",
        )
        .unwrap();
        let bumped = build(root, &Config::default());
        let report = classify_drift(&old, &bumped);
        assert!(
            report.iter().any(|l| l.starts_with("revision bump:")),
            "{report:?}"
        );
        assert!(
            report.iter().any(|l| l.contains("now SUSPECT")),
            "{report:?}"
        );
        assert_eq!(bumped.suspects.len(), 1);
    }
}
